/* 1) Styles (injected once). */
(function () {
  if (document.getElementById('cps-booking-style')) return;
  var st = document.createElement('style');
  st.id = 'cps-booking-style';
  st.textContent = "/* ---- Brand tokens — exact values from cardinalplazashell.com (Duda theme) ---- */\n  :root {\n    --cps-yellow:  #FFD305;   /* Shell yellow — primary CTA fill + border */\n    --cps-red:     #DB1D20;   /* Brand red — accent / focus */\n    --cps-ink:     #060606;   /* Primary text (near-black) */\n    --cps-gray:    #727272;   /* Muted text + headings */\n    /* --cps-gray-strong — derived contrast-safe variant of --cps-gray for\n       SMALL (<=16px) muted text only (v2 Task 13 finding 4). #727272 on\n       --cps-bg (#EEEEEE) computes to 4.15:1 — passes the 3:1 large-text\n       threshold (so headings/.cps-h3 keep --cps-gray unchanged, per design\n       contract) but fails the 4.5:1 AA threshold for normal/small text.\n       #666666 on #EEEEEE clears 4.5:1. Never used for headings. */\n    --cps-gray-strong: #666666;\n    --cps-bg:      #EEEEEE;   /* Page / modal background */\n    --cps-surface: #FFFFFF;   /* Cards / panels (also #F7F7F7 for secondary) */\n\n    --cps-line:    #E4E7EB;   /* Hairline borders */\n    --cps-ok:      #1B8A5A;   /* Success green */\n    --cps-shadow:  0 18px 50px rgba(16, 20, 28, 0.28);\n    --cps-radius:  14px;      /* Modal shell corner */\n    --cps-radius-ctl: 8px;    /* Buttons / inputs / chips */\n    --cps-font:    \"Inter\", -apple-system, BlinkMacSystemFont, \"Segoe UI\", Roboto, Helvetica, Arial, sans-serif;\n  }\n\n  /* ---- Minimal local-test launcher (not deployed to Duda) ---- */\n  .cps-local-launcher {\n    font-family: var(--cps-font);\n    background: var(--cps-bg);\n    min-height: 100vh;\n    display: flex;\n    align-items: center;\n    justify-content: center;\n    margin: 0;\n  }\n\n  /* ---- Modal overlay ---- */\n  .cps-overlay {\n    position: fixed;\n    inset: 0;\n    background: rgba(10, 12, 16, 0.62);\n    backdrop-filter: blur(3px);\n    display: none;\n    align-items: flex-start;\n    justify-content: center;\n    z-index: 99999;\n    padding: 28px 16px;\n    overflow-y: auto;\n  }\n  .cps-overlay.cps-open { display: flex; }\n\n  /* Address autocomplete — PlaceAutocompleteElement (Places API New).\n     The legacy Autocomplete dropdown was a body-appended pac-container that\n     needed a z-index bump above the 99999 overlay; the new element renders\n     its suggestion list inside its OWN shadow DOM, positioned within the\n     element and therefore inside the modal's stacking context — no page CSS\n     is needed for the dropdown, so that stale rule is deleted. Styling goes\n     through the element's documented hooks: standard host properties plus\n     ::part() (input, prediction-list, ...). Matched to the widget's control\n     look (.cps-textarea): 44px height, control radius, Inter, brand line\n     border. NOT matchable (component-internal): the focus ring geometry,\n     the built-in search icon/clear button, and the exact 1.5px inner input\n     border (the host carries the widget border instead). */\n  .cps-addr-ac {\n    display: block;\n    width: 100%;\n    box-sizing: border-box;\n    font-family: var(--cps-font);\n    color-scheme: light;\n    background-color: var(--cps-surface);\n    border: 1.5px solid var(--cps-line);\n    border-radius: var(--cps-radius-ctl);\n  }\n  .cps-addr-ac::part(input) {\n    min-height: 44px;\n    padding: 11px 12px;\n    font-family: var(--cps-font);\n    font-size: 15px;\n    color: var(--cps-ink);\n    border-radius: var(--cps-radius-ctl);\n  }\n  .cps-addr-ac::part(prediction-list) {\n    font-family: var(--cps-font);\n    font-size: 15px;\n    color: var(--cps-ink);\n    border-radius: var(--cps-radius-ctl);\n  }\n\n  /* ---- Modal shell ---- */\n  .cps-modal {\n    font-family: var(--cps-font);\n    background: var(--cps-bg);\n    width: 100%;\n    max-width: 560px;\n    border-radius: var(--cps-radius);\n    border-top: 4px solid var(--cps-yellow);\n    box-shadow: var(--cps-shadow);\n    overflow: hidden;\n    position: relative;\n    animation: cps-pop 0.22s cubic-bezier(0.2, 0.8, 0.25, 1);\n  }\n  @keyframes cps-pop {\n    from { opacity: 0; transform: translateY(14px) scale(0.985); }\n    to   { opacity: 1; transform: none; }\n  }\n\n  /* ---- Modal header ---- */\n  .cps-head {\n    background: var(--cps-surface);\n    color: var(--cps-ink);\n    padding: 16px 22px 13px;\n    position: relative;\n    border-bottom: 1px solid var(--cps-line);\n  }\n  .cps-head .cps-logo {\n    height: 34px;\n    width: auto;\n    display: block;\n    margin: 0 0 7px;\n  }\n  /* Preview feedback round 7 (item 1, the owner): the site itself renders\n     Inter at REGULAR weights, so the widget does too — every font-weight in\n     this stylesheet is 400 except .cps-btn-primary (500, the one deliberate\n     exception: 15px ink on the saturated yellow fill reads washed-out at\n     400; 500 is the lightest weight that anchors the CTA without reading\n     as bold against the site style). */\n  .cps-head .cps-shop {\n    font-size: 15px;\n    font-weight: 400;\n    color: var(--cps-ink);\n    letter-spacing: 0.01em;\n    margin: 0 0 4px;\n  }\n  .cps-head h2 {\n    margin: 0;\n    font-size: 14.5px;\n    font-weight: 400;\n    color: var(--cps-gray);\n  }\n  #cps-h2:focus { outline: none; } /* programmatic focus target only (tabindex=-1) — suppress the default ring; not keyboard-interactive */\n  .cps-x {\n    position: absolute;\n    top: 14px;\n    right: 14px;\n    width: 32px;\n    height: 32px;\n    border-radius: 50%;\n    border: 0;\n    cursor: pointer;\n    background: #EFEFEF;\n    color: #5b5b5b;\n    font-size: 18px;\n    line-height: 1;\n    display: flex;\n    align-items: center;\n    justify-content: center;\n    font-family: var(--cps-font);\n  }\n  .cps-x:hover { background: #E2E2E2; color: var(--cps-ink); }\n  /* Tap-target floor (WCAG, >=44x44) — same expanded-hit-area pattern as\n     .cps-step-btn / #cps-wg-info: keep the visible 32px circle, expand only\n     the invisible hit area via an absolutely-positioned ::before (.cps-x is\n     already `position:absolute`, so it's already a positioning context —\n     no change needed there). .cps-x sits alone in the header corner (no\n     adjacent interactive control), so the wider invisible hit area can't\n     overlap another target. */\n  .cps-x::before {\n    content: \"\";\n    position: absolute;\n    top: 50%;\n    left: 50%;\n    width: 44px;\n    height: 44px;\n    transform: translate(-50%, -50%);\n  }\n\n  /* ---- Step progress dots ---- */\n  /* 1b redesign: #cps-steps is now a block containing the bar row\n     (.cps-steps-bars) plus the caption line below it, so the flex row moves\n     to the inner wrapper. */\n  .cps-steps {\n    display: block;\n    padding: 14px 22px 0;\n  }\n  .cps-steps-bars {\n    display: flex;\n    gap: 6px;\n  }\n  /* Stepper caption (1b): names the current step and previews the next one —\n     \"STEP 2 OF 6 · TIME · NEXT: VERIFY YOUR NUMBER\". Plain '·' separators. */\n  .cps-step-caption {\n    margin: 8px 0 0;\n    font-size: 11px;\n    color: var(--cps-gray-strong);\n    letter-spacing: 0.06em;\n    text-transform: uppercase;\n  }\n\n  /* ---- Step progress dots as buttons (v2 Task 10 — clickable stepper) ----\n     The visible bar stays a thin 5px strip (unchanged look — see Task 12's\n     \"no visual redesign\" constraint); tap-target compliance (>=44x44, per\n     spec §10) is met with an invisible ::before that expands the hit area\n     without inflating the strip itself. */\n  .cps-step-btn {\n    appearance: none;\n    -webkit-appearance: none;\n    position: relative;\n    height: 5px;\n    flex: 1;\n    border: 0;\n    border-radius: 999px;\n    background: var(--cps-line);\n    transition: background 0.25s;\n    padding: 0;\n    margin: 0;\n    cursor: pointer;\n    font-family: var(--cps-font);\n  }\n  .cps-step-btn::before {\n    content: \"\";\n    position: absolute;\n    left: 0;\n    right: 0;\n    top: 50%;\n    transform: translateY(-50%);\n    min-height: 44px;\n  }\n  .cps-step-btn.cps-done   { background: #AB0000; cursor: pointer; }\n  .cps-step-btn.cps-active { background: var(--cps-red); cursor: default; }\n  .cps-step-btn:disabled   { cursor: default; }\n  .cps-step-btn.cps-done:hover { background: var(--cps-red); }\n  .cps-step-btn:disabled:not(.cps-active) { background: var(--cps-line); }\n\n  /* ---- Visually hidden (a11y live region + step-button labels) ---- */\n  .cps-sr-only {\n    position: absolute;\n    width: 1px;\n    height: 1px;\n    padding: 0;\n    margin: -1px;\n    overflow: hidden;\n    clip: rect(0, 0, 0, 0);\n    white-space: nowrap;\n    border: 0;\n  }\n\n  /* ---- Modal body + footer ---- */\n  .cps-body {\n    padding: 20px 22px 8px;\n    min-height: 230px;\n  }\n  .cps-foot {\n    display: flex;\n    gap: 10px;\n    align-items: center;\n    padding: 16px 22px 20px;\n  }\n\n  /* ---- Headings (gray, per design contract) ----\n     clamp() type scale (spec §10): desktop keeps today's exact sizes (the\n     clamp() max is each rule's pre-existing value, so >480px is visually\n     unchanged); the min is a readable floor for narrow phones, with the\n     viewport-relative middle term doing the fluid scaling in between. */\n  .cps-body h3 {\n    margin: 0 0 6px;\n    font-size: clamp(17px, 4.5vw, 20px);\n    font-weight: 400;\n    color: var(--cps-gray);\n    text-transform: uppercase;\n    letter-spacing: 0.03em;\n  }\n  .cps-steptitle {\n    font-size: clamp(19px, 5vw, 22px);\n    font-weight: 400;\n    margin: 0 0 4px;\n    color: var(--cps-gray);\n  }\n  .cps-stepsub {\n    font-size: clamp(12.5px, 3.4vw, 13.5px);\n    line-height: 1.5;\n    /* Small (<=16px) muted text — uses the AA-safe --cps-gray-strong, not\n       --cps-gray (v2 Task 13 finding 4; see :root for the contrast math). */\n    color: var(--cps-gray-strong);\n    margin: 0 0 18px;\n  }\n\n  /* ============================================================================\n     1b SECTIONED REDESIGN — shared components (design handoff\n     design_handoff_booking_widget_1b). Every content zone is a white SECTION\n     CARD with a small uppercase title; nothing floats directly on the gray\n     modal background.\n     ============================================================================ */\n  .cps-section {\n    background: var(--cps-surface);\n    border: 1.5px solid var(--cps-line);\n    border-radius: var(--cps-radius-ctl);\n    padding: 14px;\n    margin-bottom: 12px;\n  }\n  .cps-section-title {\n    margin: 0 0 10px;\n    font-size: 11px;\n    color: var(--cps-gray);\n    letter-spacing: 0.06em;\n    text-transform: uppercase;\n    font-weight: 400;\n  }\n  /* Emphasis variant — the \"Your visit so far\" basket card. */\n  .cps-section--em { border: 2px solid var(--cps-yellow); }\n\n  /* Full-width toggle tile (visit-type cards, ride, WG attestation, recs):\n     selection is conveyed by COLOR only (white -> yellow fill via .cps-sel);\n     tiles never resize on selection. Carries aria-pressed in the markup. */\n  .cps-tile {\n    display: block;\n    width: 100%;\n    text-align: left;\n    padding: 12px 14px;\n    font-size: 14px;\n    line-height: 1.45;\n  }\n  .cps-tile-title { display: block; font-size: 15px; }\n  .cps-tile-desc  { display: block; font-size: 12px; color: var(--cps-gray-strong); margin-top: 2px; line-height: 1.45; }\n  .cps-btn-ghost.cps-sel .cps-tile-desc,\n  .cps-btn-ghost.cps-sel .cps-tile-sub { color: #5b5b5b; }\n  .cps-tile-sub { display: block; font-size: 12px; color: var(--cps-gray-strong); margin-top: 2px; }\n  /* Disabled/unavailable tile: never a yellow border on something unclickable. */\n  .cps-btn-ghost.cps-tile:disabled,\n  .cps-btn-ghost.cps-tile:disabled:hover {\n    border-color: var(--cps-line);\n    color: #9a9a9a;\n    background: var(--cps-surface);\n    cursor: not-allowed;\n  }\n  .cps-btn-ghost.cps-tile:disabled .cps-tile-desc { color: #b0b0b0; }\n\n  /* Underlined text-link button (basket Remove, Resend code, Change number,\n     review-row Edit) — plain text affordances, not boxed buttons. */\n  .cps-linkbtn {\n    appearance: none;\n    background: none;\n    border: 0;\n    padding: 6px 2px;\n    font-family: var(--cps-font);\n    font-size: 13px;\n    color: var(--cps-gray);\n    text-decoration: underline;\n    cursor: pointer;\n  }\n  .cps-linkbtn:hover { color: var(--cps-ink); }\n\n  /* Error line (verify step) — red, 12px. */\n  .cps-err {\n    font-size: 12px;\n    color: var(--cps-red);\n    margin-top: 6px;\n  }\n\n  /* Calendar week (1b): MON-SUN letters row + 44px date squares, chevron\n     week nav in the section-title row. */\n  .cps-cal-head {\n    display: flex;\n    align-items: center;\n    justify-content: space-between;\n    margin: 0 0 10px;\n  }\n  .cps-cal-head .cps-section-title { margin: 0; }\n  .cps-cal-nav { display: flex; gap: 6px; }\n  .cps-wk-btn {\n    width: 32px;\n    height: 32px;\n    min-width: 32px;\n    min-height: 32px;\n    padding: 0;\n    border-radius: 50%;\n    font-size: 15px;\n    display: flex;\n    align-items: center;\n    justify-content: center;\n    position: relative;\n  }\n  /* Expanded invisible hit area (same pattern as .cps-x) so the visible\n     32px circle still meets the 44px tap-target floor. */\n  .cps-wk-btn::before {\n    content: \"\";\n    position: absolute;\n    top: 50%;\n    left: 50%;\n    width: 44px;\n    height: 44px;\n    transform: translate(-50%, -50%);\n  }\n  .cps-cal-dow {\n    font-size: 10px;\n    color: #9a9a9a;\n    text-align: center;\n    letter-spacing: 0.04em;\n  }\n\n  /* ---- Primary CTA button: yellow fill, 2px solid yellow border, 8px radius, ink text ---- */\n  /* hover inverts: white fill, yellow border, ink text */\n  .cps-btn {\n    appearance: none;\n    font-family: var(--cps-font);\n    cursor: pointer;\n    border-radius: var(--cps-radius-ctl);\n    font-size: 15px;\n    font-weight: 400;\n    padding: 12px 20px;\n    border: 2px solid transparent;\n    transition: transform 0.1s, background 0.12s, border-color 0.12s, color 0.12s;\n    /* Tap target floor (spec §10) — .cps-btn is the shared base for\n       .cps-btn-primary/.cps-btn-ghost, which in turn cover day buttons\n       (.cps-day-opt) and time-slot buttons (.cps-slot); one rule here\n       covers all of them without a visual redesign (padding already gets\n       most of the way there — this just guarantees the floor). */\n    min-height: 44px;\n    min-width: 44px;\n    box-sizing: border-box;\n  }\n  .cps-btn:active { transform: translateY(1px); }\n\n  /* PRIMARY button — matches the site theme's Primary style exactly:\n     yellow fill, 2px yellow border, black Inter text, centered, 17px, and\n     the site's signature HOVER INVERSION to a white fill (border + text\n     hold). Weight is REGULAR (400) to match the site's own button, which is\n     not bold (owner request); at 17px black on yellow stays legible. This\n     retires the last >400 weight — the whole widget is now Inter 400. */\n  .cps-btn-primary {\n    background: var(--cps-yellow);\n    color: var(--cps-ink);\n    border-color: var(--cps-yellow);\n    flex: 1;\n    font-size: 17px;\n    font-weight: 400;\n    text-align: center;\n  }\n  .cps-btn-primary:hover {\n    background: var(--cps-surface);\n    border-color: var(--cps-yellow);\n    color: var(--cps-ink);\n  }\n  .cps-btn-primary:disabled {\n    background: #F4E08C;\n    border-color: #F4E08C;\n    color: #8a8460;\n    cursor: not-allowed;\n  }\n\n  /* SECONDARY button (.cps-btn-ghost) — matches the site theme's Secondary\n     style: WHITE fill, 2px YELLOW border, black Inter text, and the hover\n     INVERSION to a yellow fill (border + text hold). This is the widget's\n     every-other-button style (Back, day tiles, time slots, handling options,\n     service tiles, add-another, week nav, Remove). Selected day/slot uses\n     .cps-sel (yellow fill) below. Disabled ghosts (unavailable/pending days,\n     capped week nav) drop to a MUTED gray outline so they never read as an\n     active yellow-bordered option. */\n  .cps-btn-ghost {\n    background: var(--cps-surface);\n    color: var(--cps-ink);\n    border-color: var(--cps-yellow);\n  }\n  .cps-btn-ghost:hover {\n    background: var(--cps-yellow);\n    border-color: var(--cps-yellow);\n    color: var(--cps-ink);\n  }\n  .cps-btn-ghost:disabled,\n  .cps-btn-ghost:disabled:hover {\n    background: var(--cps-surface);\n    border-color: var(--cps-line);\n    color: var(--cps-gray);\n    cursor: not-allowed;\n  }\n\n  /* ---- Skip link (Help + Recommended step footers) — was inline-styled\n     identically in both places (v2 Task 9 leftover); defined once here\n     (v2 Task 12 absorbed minor). Same visual as before, plus a proper\n     inline-flex + min-height so the tap target meets the 44px floor. ---- */\n  .cps-skip {\n    display: inline-flex;\n    align-items: center;\n    font-size: 13.5px;\n    color: var(--cps-gray);\n    text-decoration: underline;\n    padding: 8px 4px;\n    white-space: nowrap;\n    min-height: 44px;\n    box-sizing: border-box;\n  }\n\n  /* ---- Selected state (day/time picks): filled yellow, same as primary CTA, ---- */\n  /* so the chosen day/slot reads as \"active\" against the outlined ghost options. */\n  .cps-btn-ghost.cps-sel,\n  .cps-btn-ghost.cps-sel:hover {\n    background: var(--cps-yellow);\n    border-color: var(--cps-yellow);\n    color: var(--cps-ink);\n    font-weight: 400; /* round 7 (item 4): selection is conveyed by COLOR only — no weight change, so the tile never resizes */\n  }\n\n  /* ---- Owner tweak (2026-07-07): toggle tiles read NEUTRAL until selected ----\n     The .cps-tile group — visit-type tiles, the Need-a-ride toggle, the\n     White-Glove attestation, and the recommendation tiles — now defaults to a\n     gray hairline border. Yellow signals an ACTUAL choice, not a resting\n     default; selection (.cps-sel, above) still fills yellow. Day squares\n     (.cps-day-opt), time slots (.cps-slot), and service quick-picks\n     (.cps-svc-tile) are NOT .cps-tile, so they keep the yellow secondary-button\n     border unchanged. Hover stays subtle (gray border, white fill — never\n     yellow) so a tile only turns yellow once it's chosen. Disabled tiles keep\n     their own muted rule above. */\n  .cps-btn-ghost.cps-tile:not(.cps-sel) {\n    border-color: var(--cps-line);\n  }\n  .cps-btn-ghost.cps-tile:not(.cps-sel):not(:disabled):hover {\n    background: var(--cps-surface);\n    border-color: var(--cps-gray);\n    color: var(--cps-ink);\n  }\n\n  /* ---- Day squares (1b compact calendar week) ----\n     Every tile has IDENTICAL fixed dimensions, always (round 7 item 4 —\n     carried forward): a fixed 44px square showing only the date number, so\n     selecting a day or painting availability can never change any tile's\n     box. The per-tile \"Not available\" sublabel is RETIRED (1b) — the\n     unavailable state is the gray border + #c2c2c2 text, and the non-visual\n     signal is the aria-label (\"Monday, July 6, not available\") painted by\n     paintDayButtons. */\n  .cps-day-opt {\n    display: flex;\n    align-items: center;\n    justify-content: center;\n    height: 44px;\n    min-width: 0;\n    padding: 0;\n    font-size: 14px;\n  }\n  .cps-day-unavail,\n  .cps-day-unavail:hover {\n    border-color: var(--cps-line);\n    color: #c2c2c2;\n    background: var(--cps-surface);\n    cursor: not-allowed;\n  }\n  /* The neutral \"pending\" state every day tile renders in while the\n     availability fetch is in flight — disabled, sublabel line reserved but\n     EMPTY (no \"Not available\" yet; the one-pass paint fills it).\n     Round 8 (item 3): a subtle shimmer/pulse (the SAME cps-skel-pulse the\n     round-7 service skeletons used, brand-neutral) so the grid reads as\n     INTENTIONALLY LOADING rather than as broken, unclickable dates. The\n     fixed tile geometry is untouched — .cps-day-opt keeps its min-height and\n     the reserved sublabel line, so nothing resizes when the verdict lands\n     (paintDayButtons removes .cps-day-pending in one pass). The date label\n     stays visible under the pulse (cleaner than hiding it). Static under\n     prefers-reduced-motion (fallback below). */\n  .cps-day-pending {\n    cursor: default;\n    /* Soft gray FILL (not just an opacity fade) so a loading tile can never\n       be confused with .cps-day-unavail's flat white + gray-border look. */\n    background: #E9E9E9;\n    border-color: var(--cps-line);\n    color: var(--cps-gray);\n    animation: cps-skel-pulse 1.2s ease-in-out infinite;\n  }\n  @media (prefers-reduced-motion: reduce) {\n    .cps-day-pending { animation: none; }\n  }\n\n  /* ---- Shared loading status line (loading-ux plan Task 1): the ONE\n     loading treatment for every \"waiting on data\" text in the widget.\n     Muted gray (.cps-hint base supplies size/color), with a three-dot\n     ellipsis animated via ::after so copy stays static (\"Checking available\n     days\" + animated \"...\"). Static single ellipsis under\n     prefers-reduced-motion. Loading is never red. ---- */\n  .cps-loading::after {\n    content: \"\";\n    animation: cps-loading-dots 1.5s steps(4, end) infinite;\n  }\n  @keyframes cps-loading-dots {\n    0%   { content: \"\"; }\n    25%  { content: \".\"; }\n    50%  { content: \"..\"; }\n    75%  { content: \"...\"; }\n  }\n  @media (prefers-reduced-motion: reduce) {\n    .cps-loading::after { content: \"…\"; animation: none; }\n  }\n\n  /* ---- Slot-chip skeletons (loading-ux plan Task 2): same footprint as a\n     real .cps-slot chip so the row doesn't jump when times land. ---- */\n  .cps-slot-skel {\n    display: inline-block;\n    width: 84px;\n    height: 44px;\n    border-radius: 8px;\n    background: #E9E9E9;\n    animation: cps-skel-pulse 1.2s ease-in-out infinite;\n  }\n  @media (prefers-reduced-motion: reduce) {\n    .cps-slot-skel { animation: none; }\n  }\n\n  /* ---- Week grid (1b compact calendar): ALWAYS 7 equal columns, Mon..Sun —\n     a real calendar row (weekday letters + 44px date squares). The compact\n     squares fit 7-up at every supported width, so the old 4-column mobile\n     reflow is retired. ---- */\n  .cps-days-grid {\n    display: grid;\n    grid-template-columns: repeat(7, minmax(0, 1fr));\n    gap: 6px;\n    text-align: center;\n  }\n\n  /* ---- Wait-appointment time slots: a wrapping row with proper spacing\n     between each time (owner request), same 8px rhythm as the day grid. ---- */\n  #cps-slots {\n    display: flex;\n    flex-wrap: wrap;\n    gap: 8px;\n    margin-top: 6px;\n  }\n\n  /* ---- Quick-pick service tiles (preview feedback round 5): one tappable\n     tile per bookable service, wrapping row, brand ghost-button styling,\n     44px+ tap targets via the .cps-btn floor. ---- */\n  .cps-svc-tiles {\n    display: flex;\n    flex-wrap: wrap;\n    gap: 8px;\n    margin-top: 6px;\n  }\n  .cps-svc-tile {\n    flex: 0 1 auto;\n    font-size: 14px;\n    padding: 10px 14px;\n  }\n\n  /* ---- Non-bookable info tiles (VA Safety / Emissions inspection): live in\n     the Popular-services row so customers find them where they look, but they\n     never enter the basket — a tap opens an advisory panel instead. Styled\n     with a NEUTRAL gray outline (not the bookable tiles' yellow border) so\n     they never read as a selectable service; a tap that opens the panel\n     leaves a subtle filled/gray-border active state. ---- */\n  .cps-btn-ghost.cps-svc-tile--info {\n    border-color: var(--cps-line);\n    color: var(--cps-gray);\n  }\n  .cps-btn-ghost.cps-svc-tile--info:hover {\n    background: var(--cps-surface);\n    border-color: var(--cps-gray);\n    color: var(--cps-ink);\n  }\n  .cps-btn-ghost.cps-svc-tile--info[aria-pressed=\"true\"],\n  .cps-btn-ghost.cps-svc-tile--info[aria-pressed=\"true\"]:hover {\n    background: #F7F7F7;\n    border-color: var(--cps-gray);\n    color: var(--cps-ink);\n  }\n\n  /* ---- Shimmer/pulse keyframe (round 8 item 3): the brand-neutral loading\n     pulse. Round 7 used it on Popular-services SKELETON tiles; round 8 seeds\n     those tiles from CONFIG.popularServices so they render real from the\n     first paint (no service skeletons anymore), and this keyframe now drives\n     the DAY-GRID pending shimmer (.cps-day-pending above) — the one place\n     the customer waits on a live read. A gentle opacity pulse, disabled\n     under prefers-reduced-motion where it is declared. ---- */\n  @keyframes cps-skel-pulse {\n    0%, 100% { opacity: 1; }\n    50%      { opacity: 0.55; }\n  }\n\n  /* ---- Free-text inputs inside question/form cards (preview feedback\n     round 5, owner screenshot): an inline width:100% input with its own\n     padding + border overflows its card without border-box — pin every\n     .cps-field input (and the \"Something else\" input specifically) to the\n     card's box. ---- */\n  #cps-intake-other,\n  .cps-field input {\n    max-width: 100%;\n    box-sizing: border-box;\n  }\n\n  /* ---- Form fields ---- */\n  .cps-field { margin-bottom: 14px; }\n  .cps-field label {\n    display: block;\n    font-size: 12.5px;\n    font-weight: 400;\n    color: var(--cps-ink);\n    margin-bottom: 5px;\n  }\n\n  /* ---- Checkbox label rows (WG attest, ride, inspection add-on, intake\n     multi-choice) — the whole row is the clickable target, so it gets the\n     tap-target floor, not just the 16x16 checkbox itself. ---- */\n  .cps-check-row { min-height: 44px; box-sizing: border-box; }\n\n  .cps-textarea {\n    width: 100%;\n    box-sizing: border-box;\n    font-family: var(--cps-font);\n    font-size: 15px;\n    color: var(--cps-ink);\n    background: var(--cps-surface);\n    border: 1.5px solid var(--cps-line);\n    border-radius: var(--cps-radius-ctl);\n    padding: 11px 12px;\n    transition: border-color 0.12s;\n    resize: vertical;\n    min-height: 90px;\n  }\n  .cps-textarea:focus {\n    outline: none;\n    border-color: var(--cps-red);\n  }\n  .cps-hint {\n    font-size: 12px;\n    /* Small (<=16px) muted text — uses the AA-safe --cps-gray-strong, not\n       --cps-gray (v2 Task 13 finding 4; see :root for the contrast math). */\n    color: var(--cps-gray-strong);\n    margin-top: 6px;\n  }\n\n  /* ---- In-box send affordance for the concern textarea — a chat-style\n     submit button so the AI-intake trigger is DISCOVERABLE instead of hidden\n     behind Enter (owner feedback: easy to click Continue and lose the draft).\n     Filled yellow circle anchored bottom-right; the textarea reserves right\n     padding so typed text never slides under it. Matches the site's signature\n     hover inversion (yellow fill -> white). ---- */\n  .cps-concern-wrap { position: relative; }\n  .cps-concern-wrap .cps-textarea { padding-right: 52px; }\n  .cps-concern-send {\n    position: absolute;\n    right: 8px;\n    bottom: 8px;\n    width: 44px;\n    height: 44px;\n    min-height: 44px;\n    min-width: 44px;\n    box-sizing: border-box;\n    padding: 0;\n    display: inline-flex;\n    align-items: center;\n    justify-content: center;\n    border-radius: 50%;\n    background: var(--cps-yellow);\n    border: 2px solid var(--cps-yellow);\n    color: var(--cps-ink);\n    cursor: pointer;\n    transition: background 0.12s, border-color 0.12s, color 0.12s;\n  }\n  .cps-concern-send:hover {\n    background: var(--cps-surface);\n    border-color: var(--cps-yellow);\n    color: var(--cps-ink);\n  }\n  .cps-concern-send svg { display: block; width: 18px; height: 18px; }\n\n  /* ---- OTP PIN entry (4 boxes, one digit each) ---- */\n  .cps-pin-row { display: flex; gap: 10px; margin-top: 6px; }\n  .cps-pin-box {\n    width: 48px;\n    height: 56px;\n    min-height: 44px;\n    min-width: 44px;\n    box-sizing: border-box;\n    font-family: var(--cps-font);\n    font-size: 22px;\n    font-weight: 400;\n    text-align: center;\n    color: var(--cps-ink);\n    background: var(--cps-surface);\n    border: 1.5px solid var(--cps-line);\n    border-radius: var(--cps-radius-ctl);\n    transition: border-color 0.12s;\n  }\n  .cps-pin-box:focus {\n    outline: none;\n    border-color: var(--cps-red);\n  }\n\n  /* ---- Stub step placeholder ---- */\n  .cps-stub {\n    padding: 32px 0 8px;\n    text-align: center;\n    font-size: 14px;\n    color: var(--cps-gray);\n  }\n\n  /* ---- Confirm step: review rows (label/value pairs, no price) ---- */\n  .cps-review {\n    background: var(--cps-surface);\n    border: 1.5px solid var(--cps-line);\n    border-radius: var(--cps-radius-ctl);\n    padding: 4px 14px;\n  }\n  .cps-review-row {\n    display: flex;\n    justify-content: space-between;\n    align-items: baseline;\n    gap: 14px;\n    padding: 11px 0;\n    border-bottom: 1px solid var(--cps-line);\n  }\n  .cps-review-row:last-child { border-bottom: none; }\n  .cps-review-label {\n    font-size: 12.5px;\n    font-weight: 400;\n    color: var(--cps-gray);\n    white-space: nowrap;\n  }\n  .cps-review-value {\n    flex: 1; /* 1b: rows gained a third (Edit-link) column — the value still fills the middle, right-aligned */\n    font-size: 14.5px;\n    color: var(--cps-ink);\n    text-align: right;\n  }\n\n  /* Grouped review sections (Concerns / Services) — a titled group whose items\n     each sit on their own line with an Edit link, replacing the old\n     one-label-per-row layout and the redundant Add-ons row. Logistics rows\n     (Day / Visit type / Vehicle / Inspection) keep .cps-review-row. */\n  .cps-review-group {\n    padding: 11px 0;\n    border-bottom: 1px solid var(--cps-line);\n  }\n  .cps-review-group-title {\n    font-size: 12.5px;\n    font-weight: 400;\n    color: var(--cps-gray);\n    text-transform: uppercase;\n    letter-spacing: 0.04em;\n    margin-bottom: 4px;\n  }\n  .cps-review-item {\n    display: flex;\n    justify-content: space-between;\n    align-items: baseline;\n    gap: 14px;\n    padding: 4px 0;\n  }\n  .cps-review-item .cps-review-value { text-align: left; }\n\n  /* ---- Spinner ---- */\n  .cps-spinner {\n    width: 18px;\n    height: 18px;\n    border: 2.5px solid rgba(6, 6, 6, 0.2);\n    border-top-color: var(--cps-ink);\n    border-radius: 50%;\n    display: inline-block;\n    animation: cps-spin 0.7s linear infinite;\n    vertical-align: -3px;\n    margin-right: 8px;\n  }\n  @keyframes cps-spin { to { transform: rotate(360deg); } }\n\n  /* ---- Indeterminate progress (intake pending — preview feedback round 2).\n     Brand yellow sweep on the page-gray track, slim (4px). CSS-only; under\n     prefers-reduced-motion the sweep is replaced by a static filled track\n     (state is still conveyed by the \"One moment...\" text + announce()). ---- */\n  .cps-progress {\n    height: 4px;\n    max-width: 320px;\n    background: var(--cps-bg);\n    border-radius: 2px;\n    overflow: hidden;\n  }\n  .cps-progress-bar {\n    height: 100%;\n    width: 40%;\n    background: var(--cps-yellow);\n    border-radius: 2px;\n    animation: cps-progress-slide 1.2s ease-in-out infinite;\n  }\n  @keyframes cps-progress-slide {\n    0%   { transform: translateX(-100%); }\n    100% { transform: translateX(350%); }\n  }\n  @media (prefers-reduced-motion: reduce) {\n    .cps-progress-bar { animation: none; width: 100%; }\n  }\n\n  /* ---- Success ---- */\n  .cps-success {\n    text-align: center;\n    padding: 32px 16px 16px;\n  }\n  .cps-success .cps-circle {\n    width: 66px;\n    height: 66px;\n    border-radius: 50%;\n    background: rgba(27, 138, 90, 0.12);\n    color: var(--cps-ok);\n    display: flex;\n    align-items: center;\n    justify-content: center;\n    font-size: 28px;\n    font-weight: 400;\n    margin: 0 auto 16px;\n  }\n  .cps-success h3 {\n    margin: 0 0 8px;\n    font-size: 21px;\n    font-weight: 400;\n    color: var(--cps-ink);\n    text-transform: none;\n    letter-spacing: 0;\n  }\n  .cps-success p {\n    margin: 0 auto 6px;\n    font-size: 14.5px;\n    /* Small (<=16px) muted text — uses the AA-safe --cps-gray-strong, not\n       --cps-gray (v2 Task 13 finding 4; see :root for the contrast math). */\n    color: var(--cps-gray-strong);\n    max-width: 380px;\n    line-height: 1.5;\n  }\n\n  /* ============================================================================\n     RESPONSIVE — small phones (spec §10). Desktop (>480px) is the existing\n     centered card, untouched above this block. Below 480px the modal goes\n     near-full-screen: header + stepper stay visible, the body region\n     (#cps-bodyc) is the sole scroll container, and the footer CTA docks to\n     the bottom of the modal with safe-area padding so it clears notches/\n     home-indicators on notched phones.\n\n     Scroll-container contract: .cps-body is the ONLY thing that scrolls on\n     mobile. .cps-modal is sized to the viewport (100dvh) with\n     `display:flex;flex-direction:column`; .cps-head/.cps-steps/.cps-foot\n     are `flex:0 0 auto` (fixed size) and .cps-body is `flex:1 1 auto;\n     overflow-y:auto` (the only item that grows/scrolls). Because .cps-foot\n     is a normal flex sibling — not position:fixed/absolute — it always\n     reserves its own space below .cps-body; there's no overlap to guard\n     against with synthetic bottom-padding on .cps-body, so none is added.\n     visualViewport (below, feature-detected) only needs to nudge\n     .cps-body's scroll position when the soft keyboard opens, not touch\n     this padding contract.\n     ============================================================================ */\n  @media (max-width: 480px) {\n    .cps-overlay {\n      padding: 0;\n      align-items: stretch;\n    }\n    .cps-modal {\n      max-width: 100%;\n      height: 100vh;   /* fallback for browsers without dvh support */\n      height: 100dvh;\n      /* .cps-modal is content-box by default and carries a 4px top border\n         (desktop rule above); on mobile the height is set explicitly via\n         100vh/100dvh, so with content-box that 4px border adds ON TOP of\n         the viewport-sized height — 4px taller than the viewport, clipping\n         the sticky footer. border-box folds the border into the declared\n         height instead. */\n      box-sizing: border-box;\n      margin: 0;\n      border-radius: 0;\n      border-top-left-radius: 0;\n      border-top-right-radius: 0;\n      display: flex;\n      flex-direction: column;\n      animation: none;\n    }\n    .cps-head {\n      padding: calc(14px + env(safe-area-inset-top)) 16px 12px;\n      flex: 0 0 auto;\n    }\n    .cps-steps {\n      padding: 12px 16px 0;\n      flex: 0 0 auto;\n    }\n    .cps-body {\n      padding: 16px 16px 8px;\n      flex: 1 1 auto;\n      overflow-y: auto;\n      -webkit-overflow-scrolling: touch;\n    }\n    .cps-foot {\n      /* Pinned to the modal bottom by the flex column layout above (.cps-body\n         is the only flexible/scrolling item) — no position:sticky needed\n         since .cps-foot never sits inside the scrolling region. */\n      flex: 0 0 auto;\n      background: var(--cps-bg);\n      padding: 12px 16px calc(14px + env(safe-area-inset-bottom));\n      border-top: 1px solid var(--cps-line);\n    }\n  }";
  (document.head || document.documentElement).appendChild(st);
})();

/* 2) Widget — emitted VERBATIM at global scope (see SCOPE CONTRACT in build). */
